sub extract_pdf_info {
    my ($pdf_file) = @_;

    # Open the PDF file
    my $pdf = CAM::PDF->new($pdf_file);

    # Extract metadata
    my $docinfo = $pdf->getDocumentInfo();
    my $date = $docinfo->{'/ModDate'};
    my $author = $docinfo->{'/Author'};

    # Extract table information (example: first table in the first page)
    my $pages = $pdf->getPageContent(1);
