        my $table_info = extract_tables($pages);
        return ($date, $author, $table_info);
    } else {
        return ($date, $author, 'No table found');
    }
}

# Function to extract tables from PDF content
sub extract_tables {
    my ($content) = @_;

    # This is a simple regex to identify tables. You may need to adjust it based on the structure of your PDF.
    my $table_pattern = qr/(\d+\s+\d+\s+\d+)/; # Example pattern to find table cells

    # Apply the regex to find table information
    if ($content =~ /$table_pattern/g) {
        my @matches = ($&);
        return join(", ", @matches);
    } else {
        return 'No table found';
    }
}

